import{C as t}from"./content-DQ4bI-ON.js";document.title=t.siteTitle;document.getElementById("back-link").innerHTML=t.contact.backLabel;const d=document.getElementById("contact-links");t.links.forEach(n=>{const e=document.createElement("a");e.href=n.url,e.target="_blank",e.innerHTML="&#x2197;&#xFE0E; "+n.label,d.appendChild(e)});document.getElementById("contact-image").alt=t.contact.imageAlt;document.getElementById("contact-note").textContent=t.contact.note;const r=document.getElementById("footer"),o=document.createElement("h2");o.className="reveal reveal-delay-3";const l=document.createElement("a");l.href="mailto:"+t.email;l.target="_blank";l.innerHTML="&#x2197;&#xFE0E; "+t.email;o.appendChild(l);r.appendChild(o);const c=document.createElement("h2");c.className="reveal reveal-delay-4";const a=document.createElement("a");a.href="bloopers.html";a.textContent=t.year;a.style.color="#000000";a.style.textDecoration="none";c.appendChild(a);r.appendChild(c);const m=new IntersectionObserver(n=>{n.forEach(e=>{e.isIntersecting&&(e.target.classList.add("visible"),m.unobserve(e.target))})},{threshold:.15});document.querySelectorAll(".reveal").forEach(n=>m.observe(n));
